        0x60, 0x00, 0x00, // type 0: 0 params, 0 results
        0x60, 0x02, 0x7F, 0x7E, 0x00, // type 1: i32+i64 params, 0 results
        // tag section: count=3; (0,0), (0,1), (0,0)
        0x0D, 0x07, 0x03, 0x00, 0x00,
        0x00, 0x01, 0x00, 0x00,
