        // global mut i32 = 0
        0x06, 0x06, 0x01, 0x7f, 0x01, 0x41, 0x00, 0x0b,
        // export sec: "set" func0, "get" func1
        0x07, 0x0d, 0x02, 0x03, 0x73, 0x65, 0x74, 0x00,
        0x00, 0x03, 0x67, 0x65, 0x74, 0x00, 0x01,
