        0x0a,
        0x0d, 0x02,
        0x06, 0x00, 0x20, 0x00, 0x24, 0x00, 0x0b, // set: local.get 0; global.set 0
        0x04, 0x00, 0x23, 0x00, 0x0b, // get: global.get 0
    };
    var inst = try JitInstance.init(testing.allocator, &bytes);
    defer inst.deinit(testing.allocator);
    try testing.expectEqual(@as(?u64, null), try inst.invoke(testing.allocator, "set", &.{77}));
    try testing.expectEqual(@as(?u64, 77), try inst.invoke(testing.allocator, "get", &.{}));
}

test "JitInstance.invoke: mem64 OOB i32.load traps (D-234 corpus-path repro)" {
    if (builtin.os.tag == .windows) return skip.phaseEnd(.win64);
    // (module (memory i64 1) (func (export "i32.load") (param $a i64) (result i32)
    //   (i32.load (local.get $a))))  — invoke "i32.load" with 0x10000 (OOB) → must trap.
    // This is the EXACT corpus path (JitInstance.invoke on a kept instance) where
    // the 51 memory64 assert_trap fails live; the fresh-setupRuntime siblings trap
    // fine. If this RETURNS instead of trapping, D-234 is reproduced in the JIT
    // path; if it TRAPS, the corpus issue is in the runner's per-assert reuse.
    const bytes = [_]u8{
        0x00, 0x61, 0x73, 0x6d, 0x01, 0x00, 0x00, 0x00,
        0x01, 0x06, 0x01, 0x60, 0x01, 0x7e, 0x01, 0x7f, // type (i64)->i32
        0x03, 0x02, 0x01, 0x00, // func
        0x05, 0x03, 0x01, 0x04, 0x01, // memory i64 1
        // export "i32.load" (8 bytes) func 0
        0x07, 0x0c, 0x01, 0x08, 0x69,
        0x33, 0x32, 0x2e, 0x6c, 0x6f,
        0x61, 0x64, 0x00, 0x00,
        // code: local.get 0; i32.load; end
        0x0a,
        0x09, 0x01, 0x07, 0x00, 0x20,
        0x00, 0x28, 0x02, 0x00, 0x0b,
    };
    var inst = try JitInstance.init(testing.allocator, &bytes);
    defer inst.deinit(testing.allocator);
    // The corpus invokes a trap-func MANY times on the same kept instance. A JIT
    // trap must leave the instance re-invokable (trap_flag reset). Three OOB
    // invokes must ALL trap; a non-trap on the 2nd/3rd = the D-234 root cause.
    try testing.expectError(error.Trap, inst.invoke(testing.allocator, "i32.load", &.{0x10000}));
    try testing.expectError(error.Trap, inst.invoke(testing.allocator, "i32.load", &.{0x10000}));
    try testing.expectError(error.Trap, inst.invoke(testing.allocator, "i32.load", &.{0x10000}));
    // The corpus runs IN-BOUNDS asserts before the OOB traps on the same instance.
    _ = try inst.invoke(testing.allocator, "i32.load", &.{0}); // in-bounds
    try testing.expectError(error.Trap, inst.invoke(testing.allocator, "i32.load", &.{0x10000})); // OOB after in-bounds
}

// ── ADR-0128 §1 / D-215: real JIT memory.grow (realloc + persist + max) ──

test "JitInstance: memory.grow grows + persists, memory.size reflects it" {
    if (builtin.os.tag == .windows) return skip.phaseEnd(.win64);
    // (module (memory 0)
    //   (func (export "g") (param i32) (result i32) local.get 0 memory.grow)
    //   (func (export "s") (result i32) memory.size))
    // Default memory_grow_fn rejected (returned -1); a real one grows the
    // realloc'd buffer and updates rt.vm_base/mem_limit so size persists.
    const bytes = [_]u8{
        0x00, 0x61, 0x73, 0x6d, 0x01, 0x00, 0x00, 0x00,
        0x01, 0x0a, 0x02, 0x60, 0x01, 0x7f, 0x01, 0x7f,
        0x60, 0x00, 0x01, 0x7f, 0x03, 0x03, 0x02, 0x00,
        0x01,
        0x05, 0x03, 0x01, 0x00, 0x00, // memory: min 0, no max
        0x07, 0x09, 0x02, 0x01, 0x67, 0x00, 0x00, 0x01, 0x73, 0x00, 0x01, // exports g,s
        0x0a, 0x0d, 0x02,
        0x06, 0x00, 0x20, 0x00, 0x40, 0x00, 0x0b, // g: local.get 0; memory.grow 0
        0x04, 0x00, 0x3f, 0x00, 0x0b, // s: memory.size 0
    };
    var inst = try JitInstance.init(testing.allocator, &bytes);
    defer inst.deinit(testing.allocator);
    try testing.expectEqual(@as(?u64, 0), try inst.invoke(testing.allocator, "s", &.{})); // size 0
    try testing.expectEqual(@as(?u64, 0), try inst.invoke(testing.allocator, "g", &.{1})); // grow→old 0
    try testing.expectEqual(@as(?u64, 1), try inst.invoke(testing.allocator, "s", &.{})); // size 1 (persisted)
    try testing.expectEqual(@as(?u64, 1), try inst.invoke(testing.allocator, "g", &.{1})); // grow→old 1
    try testing.expectEqual(@as(?u64, 2), try inst.invoke(testing.allocator, "s", &.{})); // size 2
}

test "JitInstance: memory.grow past declared max returns -1" {
    if (builtin.os.tag == .windows) return skip.phaseEnd(.win64);
    // (module (memory 0 1) (func (export "g") (param i32) (result i32) local.get 0 memory.grow))
    const bytes = [_]u8{
        0x00, 0x61, 0x73, 0x6d, 0x01, 0x00, 0x00, 0x00,
        0x01, 0x06, 0x01, 0x60, 0x01, 0x7f, 0x01, 0x7f,
        0x03, 0x02, 0x01, 0x00,
        0x05, 0x04, 0x01, 0x01, 0x00, 0x01, // memory: flag=has_max, min 0, max 1
        0x07, 0x05, 0x01, 0x01, 0x67, 0x00,
        0x00, 0x0a, 0x08, 0x01, 0x06, 0x00,
        0x20, 0x00, 0x40, 0x00, 0x0b,
    };
    var inst = try JitInstance.init(testing.allocator, &bytes);
    defer inst.deinit(testing.allocator);
    try testing.expectEqual(@as(?u64, 0), try inst.invoke(testing.allocator, "g", &.{1})); // 0→1 ok, old 0
    // grow by 1 more → 2 > max 1 → -1 (i32 -1 = 0xffffffff zero-extended in the carrier)
    try testing.expectEqual(@as(?u64, 0xffffffff), try inst.invoke(testing.allocator, "g", &.{1}));
}

// ── ADR-0128 §1 / D-216 Part B: memory64 grow -1 result i64 sign-extension ──

test "JitInstance: memory64 grow past max returns i64 -1 (sign-extended, not 0x0000_0000ffffffff)" {
    if (builtin.os.tag == .windows) return skip.phaseEnd(.win64);
    // (module (memory i64 0 1)
    //   (func (export "g") (param i64) (result i64) local.get 0 memory.grow))
    // memory64 grow result is i64; the -1 failure sentinel must widen to a
    // full i64 -1 (0xffff_ffff_ffff_ffff), not the i32 -1 zero-extended to
    // 0x0000_0000_ffff_ffff that the pre-D-216 zero-ext capture produced.
    const bytes = [_]u8{
        0x00, 0x61, 0x73, 0x6d, 0x01, 0x00, 0x00, 0x00,
        0x01, 0x06, 0x01, 0x60, 0x01, 0x7e, 0x01, 0x7e, // type (i64)->(i64)
        0x03, 0x02, 0x01, 0x00,
        0x05, 0x04, 0x01, 0x05, 0x00, 0x01, // memory: flag=mem64|has_max, min 0, max 1
        0x07, 0x05, 0x01, 0x01, 0x67, 0x00,
        0x00, 0x0a, 0x08, 0x01, 0x06, 0x00,
        0x20, 0x00, 0x40, 0x00, 0x0b,
    };
    var inst = try JitInstance.init(testing.allocator, &bytes);
    defer inst.deinit(testing.allocator);
    try testing.expectEqual(@as(?u64, 0), try inst.invoke(testing.allocator, "g", &.{1})); // 0→1 ok, old 0
    // grow → 2 > max 1 → i64 -1 = all-ones (the sign-extension under test)
    try testing.expectEqual(@as(?u64, 0xffffffffffffffff), try inst.invoke(testing.allocator, "g", &.{1}));
}

