// ── ADR-0128 §1 / D-219: memory64 active-data offset is i64 (JIT compile gate) ──

test "JitInstance: memory64 module with active data at i64 offset compiles + loads" {
    if (builtin.os.tag == .windows) return skip.phaseEnd(.win64);
    // (module (memory i64 1)
    //   (data (i64.const 0) "\2a\00\00\00")   ;; 42 at addr 0 (offset expr is i64!)
    //   (func (export "ld") (result i32) i64.const 0 i32.load))
    // The JIT compile gate validated active-data offset exprs against i32,
    // rejecting the memory64 i64.const offset with InvalidGlobalInitExpr (D-219).
    // (i32.load — supported on mem64 per D-181; load8/16 are a separate gap.)
    const bytes = [_]u8{
        0x00, 0x61, 0x73, 0x6d, 0x01, 0x00, 0x00, 0x00,
        0x01, 0x05, 0x01, 0x60, 0x00, 0x01, 0x7f, // type ()->(i32)
        0x03, 0x02, 0x01, 0x00,
        0x05, 0x03, 0x01, 0x04, 0x01, // memory: flag=0x04 (i64), min 1
        0x07, 0x06, 0x01, 0x02, 0x6c, 0x64, 0x00, 0x00, // export "ld"
        0x0a, 0x09, 0x01, 0x07, 0x00, 0x42, 0x00, 0x28, 0x02, 0x00, 0x0b, // i64.const 0; i32.load align=2 off=0
        // data sec: 1 active seg, memidx 0, offset (i64.const 0), bytes "\2a\00\00\00"
        0x0b, 0x0a, 0x01, 0x00, 0x42, 0x00, 0x0b, 0x04, 0x2a, 0x00, 0x00,
        0x00,
    };
    var inst = try JitInstance.init(testing.allocator, &bytes);
    defer inst.deinit(testing.allocator);
    try testing.expectEqual(@as(?u64, 42), try inst.invoke(testing.allocator, "ld", &.{}));
}

test "JitInstance.invokeMulti: 2-result (i32 i32) returns both values via entry_buf (ADR-0106 cycle 3 — multi-value JIT corpus)" {
    if (builtin.os.tag == .windows) return skip.phaseEnd(.win64);
    // (module (func (export "pair") (result i32 i32) i32.const 7 i32.const 9))
    // The single-result `invoke` rejects results.len>1; multi-value
    // reuses the ADR-0106 wrapper-thunk buffer-write entry (entry_buf).
    const bytes = [_]u8{
        0x00, 0x61, 0x73, 0x6d, 0x01, 0x00, 0x00, 0x00, // \0asm + version
        // type sec: 1 type, () -> (i32 i32)
        0x01, 0x06, 0x01, 0x60, 0x00, 0x02, 0x7f, 0x7f,
        // func sec: 1 func, type 0
        0x03, 0x02, 0x01, 0x00,
        // export sec: 1 export, name="pair", kind=func, idx=0
        0x07, 0x08, 0x01, 0x04,
        0x70, 0x61, 0x69, 0x72, 0x00, 0x00,
        // code sec: 1 body, size 6: locals=0, i32.const 7, i32.const 9, end
        0x0a, 0x08,
        0x01, 0x06, 0x00, 0x41, 0x07, 0x41, 0x09, 0x0b,
    };
    var inst = try JitInstance.init(testing.allocator, &bytes);
    defer inst.deinit(testing.allocator);
    var results = [_]TypedResult{ undefined, undefined };
    try inst.invokeMulti(testing.allocator, "pair", &.{}, &results);
    try testing.expectEqual(@as(u32, 7), results[0].i32);
    try testing.expectEqual(@as(u32, 9), results[1].i32);
}

test "JitInstance.invokeMulti: 1-param 2-result returns (arg, 42) — arm64 param-bearing wrapper thunk" {
    // arm64-only: the param-bearing multi-value wrapper thunk is emitted by
    // `emitAarch64` (AAPCS). The x86_64 SysV path still rejects params (NO_THUNK
    // → invokeMulti skips), so this shape is unsupported there (D-229). Mirrors
    // the existing per-arch byte tests' gating.
    // SIBLING-AT: src/engine/codegen/shared/wrapper_thunk.zig (x86_64 SysV param-bearing thunk: D-229)
    if (comptime builtin.cpu.arch != .aarch64) return;
    if (builtin.os.tag == .windows) return skip.phaseEnd(.win64);
    // (module (func (export "swap") (param i32) (result i32 i32)
    //   (local.get 0) (i32.const 42)))
    // Exercises the param-bearing wrapper thunk: param0 loaded from the
    // buffer-write args ptr into the body's X1 (AAPCS), results in X0/X1.
    // (const 42 = 0x2a, single-byte SLEB128 positive; 0x64 would be -28.)
    const bytes = [_]u8{
        0x00, 0x61, 0x73, 0x6d, 0x01, 0x00, 0x00, 0x00, // \0asm + version
        // type sec: 1 type, (i32) -> (i32 i32)
        0x01, 0x07, 0x01, 0x60, 0x01, 0x7f, 0x02, 0x7f,
        0x7f,
        // func sec: 1 func, type 0
        0x03, 0x02, 0x01, 0x00,
        // export sec: 1 export, name="swap", kind=func, idx=0
        0x07, 0x08, 0x01,
        0x04, 0x73, 0x77, 0x61, 0x70, 0x00, 0x00,
        // code sec: 1 body, size 6: locals=0, local.get 0, i32.const 42, end
        0x0a,
        0x08, 0x01, 0x06, 0x00, 0x20, 0x00, 0x41, 0x2a,
        0x0b,
    };
    var inst = try JitInstance.init(testing.allocator, &bytes);
    defer inst.deinit(testing.allocator);
    var results = [_]TypedResult{ undefined, undefined };
    try inst.invokeMulti(testing.allocator, "swap", &.{5}, &results);
    try testing.expectEqual(@as(u32, 5), results[0].i32);
    try testing.expectEqual(@as(u32, 42), results[1].i32);
}
